const crypto = require\('crypto'\);
const QR_SECRET = '27f000a81860f2c7fa9f14fafa2028dc77b38b96195a99c250a60b28a781fef2';
const OFFICE_ID = 'ASKWORX_HQ';

function getTodayDateString\(\) {
  return new Date\(\).toISOString\(\).slice\(0, 10\);
}
function generateDailyToken\(date\) {
  return crypto.createHmac\('sha256', QR_SECRET\).update\(date\).digest\('hex'\).slice\(0, 32\);
}
function buildQRContent\(\) {
  const date = getTodayDateString\(\);
  const token = generateDailyToken\(date\);
  return OFFICE_ID + ':' + token;
}
function validateQRContent\(content\) {
  const colonIdx = content.indexOf\(':'\);
  if \(colonIdx === -1\) return { valid: false, token: null };
  const officeId = content.slice\(0, colonIdx\);
  const scannedToken = content.slice\(colonIdx + 1\);
  if \(officeId !== OFFICE_ID\) return { valid: false, token: null };
  const expectedToken = generateDailyToken\(getTodayDateString\(\)\);
  if \(scannedToken !== expectedToken\) return { valid: false, token: null };
  return { valid: true, token: scannedToken };
}

const qr = buildQRContent\(\);
console.log\('QR Content:', qr\);
console.log\('Token length:', qr.split\(':'\)[1].length\);

// Validate correct QR
const result = validateQRContent\(qr\);
console.log\('Valid QR result:', result\);

// Validate wrong token
const badResult = validateQRContent\(OFFICE_ID + ':' + 'deadbeefdeadbeefdeadbeefdeadbeef'\);
console.log\('Invalid token result:', badResult\);

// Validate wrong office
const wrongOffice = validateQRContent\('WRONG_OFFICE:' + qr.split\(':'\)[1]\);
console.log\('Wrong office result:', wrongOffice\);

// Test with OFFICE_ID containing colon \(edge case\)
const colonOfficeQR = 'ASK:WORX:' + qr.split\(':'\)[1];
const colonOfficeResult = validateQRContent\(colonOfficeQR\);
console.log\('Colon-in-office-id \(should be invalid\):', colonOfficeResult\);
")
